vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
//vUv = (vUv-0.5) * uAspect.xy + .5;
dz = 0;


vec2 hor = vec2(uTexSize.z,0);
vec2 ver = vec2(0,uTexSize.w);

float dist = 1;
float inten = 1;
ret1 = 0;
float anz = 1;
float n = 0;
//vUv = multiply(vUv-.5, mat2(_qa))+.5;
float z = vUv.y/2+1; z = z/1.2; z = 1;
uv4 = vec2((vUv.x-.5)/z+.5,vUv.y/z);
    dz.x = lum(GetPixel(uv4+hor)- GetPixel (uv4-hor));
    dz.y = lum(GetPixel(uv4+ver)- GetPixel (uv4-ver));

//uv4 = 0;

mus = 1*GetPixel(uv4+.2*dz)-q1*1*dz.y+.04;

uv2 = vUv-.5;
    dist = 1-fract(1.0/anz*n-.1); //evtl sqrt !;

    inten =  sqrt(dist)*(1-dist*dist)*4;


    uv3 = .4 * cos(42*uv3) + 64*dz;
    neu = clamp01(.01/length(uv3)) ;
    neu = dist*neu + (1-dist)*lum(neu);
    ret1 = max(ret1,neu*inten);


ret = -0*ret1  +  clamp01(12*mus*(.1+ret1))-.05;

  fragColor = ret;
